INTO CORDYS.SUG_BOX_PERSONAL (
    SBP_NO
    , TITLE
    , CATEGORY
    , STATUS
    , SUGGESTION
    , FILE1
    , FILE2
    , FILE3
    , BROKER_CODE
    , INTERMEDIARY_EMP_CD
    , ANS_UPDATE_TIME
    , CREATE_TIME
    , CREATE_USER
    , UPDATE_TIME
    , UPDATE_USER
)
VALUES(
    TO_NUMBER(#{req.sbpNo})
    , #{req.title}
    , #{req.category}
    , '0'
    , #{req.suggestion}
    , #{req.registerFileName1}
    , #{req.registerFileName2}
    , #{req.registerFileName3}
    , #{req.brokerCode}
    , #{req.intermediaryEmpCd}
    , null
    , IFA_DATE_UTIL.IFA_GET_DATE
    , #{req.userId}
    , IFA_DATE_UTIL.IFA_GET_DATE
    , #{req.userId}
)
